DarkRPUI.HUD.RegisterElement("main",{paint=function(ply) if not IsValid(ply) then return end local sx,sy,sw,sh=DarkRPUI.Layout.GetSafeRect(); local x,y,w,h=DarkRPUI.Layout.ClampRect(sx,sy+sh-126,430,124,true); DarkRPUI.UI.ShadowedBox(20,x,y,w,h,DarkRPUI.WithAlpha(DarkRPUI.Color("panel"),240),DarkRPUI.Color("border"),125); surface.SetDrawColor(team.GetColor(ply:Team())); surface.DrawRect(x,y+12,5,h-24); DarkRPUI.UI.Text(ply:Nick(),"DarkRPUI.Subtitle",x+18,y+12); DarkRPUI.UI.Text(team.GetName(ply:Team()) or "Citizen","DarkRPUI.Small",x+18,y+40,team.GetColor(ply:Team())); DarkRPUI.UI.Text(DarkRPUI.Util.FormatMoney(DarkRPUI.Util.DarkRPVar(ply,"money",0)),"DarkRPUI.Number",x+w-18,y+14,DarkRPUI.Color("success"),TEXT_ALIGN_RIGHT); DarkRPUI.UI.RoundedBox(6,x+18,y+78,180,10,DarkRPUI.Color("border")); DarkRPUI.UI.RoundedBox(6,x+18,y+78,180*math.Clamp(ply:Health()/100,0,1),10,DarkRPUI.Color("success")); DarkRPUI.UI.RoundedBox(6,x+220,y+78,180,10,DarkRPUI.Color("border")); DarkRPUI.UI.RoundedBox(6,x+220,y+78,180*math.Clamp(ply:Armor()/100,0,1),10,DarkRPUI.Color("accent")) end})
